'use client';

import Image from 'next/image';
import Link from 'next/link';
import { motion } from 'framer-motion';
import { ChevronRight, MapPin, Package } from 'lucide-react';
import type { Cooperative } from '../data/mockData';

type ZoneCooperativesCardsProps = {
  cooperatives: Cooperative[];
};

export default function ZoneCooperativesCards({ cooperatives }: ZoneCooperativesCardsProps) {
  return (
    <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
      {cooperatives.map((coop, index) => (
        <motion.div
          key={coop.id}
          initial={{ opacity: 0, y: 12 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.3, delay: index * 0.06 }}
        >
          <Link
            href={`/cooperative/${coop.slug}`}
            className="group flex overflow-hidden rounded-2xl border border-white/50 bg-white/80 shadow-soft transition hover:border-terracotta/30 hover:shadow-lg"
          >
            <div className="relative h-24 w-28 shrink-0 overflow-hidden sm:h-28 sm:w-32">
              <Image
                src={coop.coverImage}
                alt={coop.coverAlt}
                fill
                sizes="128px"
                className="object-cover transition duration-500 group-hover:scale-105"
              />
            </div>
            <div className="flex min-w-0 flex-1 flex-col justify-center p-4">
              <span className="text-xs font-medium uppercase tracking-wide text-terracotta">
                {coop.category}
              </span>
              <h3 className="mt-0.5 line-clamp-2 font-semibold text-palmier group-hover:text-terracotta">
                {coop.name}
              </h3>
              <div className="mt-1 flex items-center gap-3 text-xs text-palmier/70">
                <span className="inline-flex items-center gap-1">
                  <MapPin size={12} />
                  {coop.location.address.split(',')[0]}
                </span>
                <span className="inline-flex items-center gap-1">
                  <Package size={12} />
                  {coop.products.length} produits
                </span>
              </div>
              <span className="mt-2 inline-flex items-center gap-1 text-sm font-medium text-terracotta">
                Voir la coopérative
                <ChevronRight size={14} className="transition group-hover:translate-x-1" />
              </span>
            </div>
          </Link>
        </motion.div>
      ))}
    </div>
  );
}
